def _get_estate(slug: str):
    return ESTATES.get(slug)


def _get_page_content_html(car_park, page_key: str) -> str:
    """Return owner-saved HTML for a sub-page content block, or empty string."""
    import json as _json
    if not car_park or not getattr(car_park, "page_contents", None):
        return ""
    try:
        contents = _json.loads(car_park.page_contents)
        return contents.get(page_key, "")
    except Exception:
        return ""


def _resolve_features(car_park, estate: dict) -> list:
    """Return features list: use car_park.custom_features if set, else ESTATES dict."""
    import json as _json
    if car_park and getattr(car_park, "custom_features", None):
        try:
            return _json.loads(car_park.custom_features)
        except Exception:
            pass
    return estate.get("features", [])


def _get_brand(estate: dict, car_park) -> dict:
    """Return brand colours from DB for onboarded estates; None for all others."""
    if car_park:
        return {
            "primary": car_park.brand_primary or "#000",
            "accent":  car_park.brand_accent  or "#B89A5A",
            "text":    car_park.brand_text    or "#ffffff",
        }
    return None


def _haversine_km(lat1: float, lng1: float, lat2: float, lng2: float) -> float:
    dlat = math.radians(lat2 - lat1)
    dlng = math.radians(lng2 - lng1)
    a = math.sin(dlat / 2) ** 2 + math.cos(math.radians(lat1)) * math.cos(math.radians(lat2)) * math.sin(dlng / 2) ** 2
    return 6371 * 2 * math.asin(math.sqrt(a))


def _get_nearby_estates(slug: str, estate: dict, n: int = 4) -> list:
    e_lat, e_lng = estate.get("lat", 0.0), estate.get("lng", 0.0)
    result = []
    for other_slug, other in ESTATES.items():
        if other_slug == slug:
            continue
        dist = _haversine_km(e_lat, e_lng, other.get("lat", 0.0), other.get("lng", 0.0))
        dist_label = f"{dist:.0f} km away" if dist >= 1 else f"{int(dist * 1000)} m away"
        result.append({
            "slug": other_slug,
            "name": other["name"],
            "county": other.get("county", ""),
            "tagline": other.get("tagline", ""),
            "brand_accent": other.get("brand_accent", "#B89A5A"),
            "dist_km": dist,
            "dist_label": dist_label,
        })
    result.sort(key=lambda x: x["dist_km"])
    return result[:n]


def _estate_initials(name: str) -> str:
    skip = {"the", "a", "an", "of", "and", "&"}
    words = [w for w in name.split() if w.lower() not in skip]
    return "".join(w[0] for w in words[:2]).upper()


def _base_ctx(request, slug: str, estate: dict, car_park, page_name: str = "") -> dict:
    """Common template context shared by every visitor page."""
    hero_image_url = ""
    hist = HISTORY.get(slug, {})
    if isinstance(hist, dict):
        chaps = hist.get("chapters", [])
        if chaps and chaps[0].get("image_url"):
            hero_image_url = chaps[0]["image_url"]
    logo = (getattr(car_park, "logo_url", None) or "") if car_park else ""
    if not logo:
        logo = estate.get("logo_url", "") if estate else ""
    if not logo:
        logo = f"/location/{slug}/mark.svg"
    return {
        "request":    request,
        "slug":       slug,
        "estate":     estate,
        "estate_name": car_park.owner.name if car_park else estate["name"],
        "car_park_name": page_name,
        "logo_url":   logo,
        "cp_slug":    estate.get("car_park_slug", "") or "",
        "brand":      _get_brand(estate, car_park),
        "features":   _resolve_features(car_park, estate),
        "hero_image_url": hero_image_url,
        "nearby_estates": _get_nearby_estates(slug, estate),
        "ad_slot_html": None,
    }


