@router.post("/{slug}/visitor/sponsor-a-bench")
async def visitor_bench_enquiry(slug: str, request: Request, db: Session = Depends(get_db)):
    from fastapi.responses import JSONResponse
    from ..models import BenchEnquiry
    estate = _get_estate(slug)
    if not estate:
        return JSONResponse({"error": "Estate not found"}, status_code=404)
    try:
        body = await request.json()
    except Exception:
        return JSONResponse({"error": "Invalid request"}, status_code=400)

    name = str(body.get("name", "")).strip()[:200]
    email = str(body.get("email", "")).strip()[:200]
    if not name or not email or "@" not in email:
        return JSONResponse({"error": "Name and valid email are required"}, status_code=400)

    enquiry = BenchEnquiry(
        estate_slug=slug,
        name=name,
        email=email,
        location_slug=str(body.get("location", "")).strip()[:100] or None,
        bench_type_slug=str(body.get("bench_type", "")).strip()[:100] or None,
        inscription=str(body.get("inscription", "")).strip()[:40] or None,
        notes=str(body.get("notes", "")).strip()[:1000] or None,
    )
    db.add(enquiry)
    db.commit()
    return JSONResponse({"ok": True})


@router.get("/{slug}/visitor/legacy", response_class=HTMLResponse)
def visitor_legacy(request: Request, slug: str, donated: str = "", db: Session = Depends(get_db)):
    from ..models import Donation, DonationStatus
    estate = _get_estate(slug)
    if not estate:
        return RedirectResponse(url="/", status_code=302)
    cp_slug = estate.get("car_park_slug")
    car_park = db.query(CarPark).filter(CarPark.slug == cp_slug).first() if cp_slug else None
    if donated and donated.startswith("cs_"):
        donation = db.query(Donation).filter(Donation.stripe_session_id == donated).first()
        if donation and donation.status == DonationStatus.pending:
            donation.status = DonationStatus.paid
            db.commit()
    ctx = _base_ctx(request, slug, estate, car_park, "Legacy")
    ctx["page_content_html"] = _get_page_content_html(car_park, "legacy")
    ctx["donated"] = bool(donated)
    return templates.TemplateResponse("location/visitor/legacy.html", ctx)


@router.get("/{slug}/visitor/parking-receipt", response_class=HTMLResponse)
def visitor_parking_receipt(request: Request, slug: str, txn: str = None, db: Session = Depends(get_db)):
    from datetime import timedelta, timezone as _tz
    estate = _get_estate(slug)
    if not estate:
        return RedirectResponse(url="/", status_code=302)
    cp_slug = estate.get("car_park_slug")
    car_park = db.query(CarPark).filter(CarPark.slug == cp_slug).first() if cp_slug else None
    accent = (car_park.brand_accent or "#8B3A2A") if car_park else "#8B3A2A"

    plate, valid_until, amount_str, reference = "", "", "", ""

    if txn:
        try:
            stripe.api_key = os.getenv("STRIPE_SECRET_KEY")
            session = stripe.checkout.Session.retrieve(txn)
            txn_id = (session.metadata or {}).get("txn_id")
            if txn_id:
                transaction = db.query(Transaction).filter(Transaction.id == int(txn_id)).first()
                if transaction:
                    if transaction.status == TransactionStatus.pending:
                        now = datetime.now(timezone.utc)
                        transaction.status = TransactionStatus.paid
                        transaction.parked_at = now
                        if transaction.is_all_day:
                            transaction.expires_at = now.replace(hour=23, minute=59, second=59, microsecond=0)
                        elif transaction.duration_hours:
                            transaction.expires_at = now + timedelta(hours=transaction.duration_hours)
                        db.commit()
                        db.refresh(transaction)
                    plate = transaction.number_plate
                    amount_str = f"£{transaction.amount_pence / 100:.2f}"
                    reference = f"PKC-{transaction.id:05d}"
                    if transaction.expires_at:
                        valid_until = transaction.expires_at.strftime("%a %d %b %Y at %H:%M")
                    elif transaction.is_all_day:
                        valid_until = "End of day"
        except Exception:
            pass

    return templates.TemplateResponse("driver/receipt_placeholder.html", {
        "request": request,
        "slug": slug,
        "estate_name": car_park.owner.name if car_park else "",
        "car_park_name": car_park.name if car_park else "",
        "logo_url": (getattr(car_park, "logo_url", None) or "") if car_park else "",
        "brand": {"accent": accent},
        "plate": plate,
        "valid_until": valid_until,
        "amount": amount_str,
        "reference": reference,
    })
